mapper.select:
SELECT * FROM user_email
WHERE user_id = #{userId}
  AND email_type = #{emailType}
  AND status = 1
ORDER BY id DESC
LIMIT 1

mapper.update:
UPDATE user_email
SET status = 0,
    update_time = CURRENT_TIMESTAMP(3)
WHERE user_id = #{userId}
  AND email_type = #{emailType}
  AND status = 1
